using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change #1: EF Core 9 renames the discriminator property
            // from "Discriminator" to "$type". Existing 500K documents use
            // "Discriminator", and direct SQL queries reference c.Discriminator.
            // Preserve the old property name for backward compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #2: EF Core 9 changes the id format from
            // "Product|123" to just "123". Existing documents use the old format.
            // Preserve the old format so existing documents remain accessible.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();
        });

        // Breaking change #3: HasIndex is not supported by the Cosmos provider.
        // EF Core 9 throws instead of silently ignoring it. Removed.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

